import React from 'react';
import { ButtonGroup, Button } from '@salutejs/plasma-web';
export function App() {
    return (
        <ButtonGroup>
            {Array(5)
                .fill(true)
                .map((_, i) => (
                    <Button text={`Button ${i}`} />
                ))}
        </ButtonGroup>
    );
}

import React from 'react';
import { ButtonGroup, Button } from '@salutejs/plasma-web';
export function App() {
    return (
        <div>
            <ButtonGroup size="s" view="secondary">
                {Array(5)
                    .fill(true)
                    .map((_, i) => (
                        <Button text={`Button ${i}`} />
                    ))}
            </ButtonGroup>
            <ButtonGroup isCommonButtonStyles={false}>
                <Button size="m" text="Default" />
                <Button size="s" text="Primary" view="default" />
                <Button size="xs" text="Success" view="success" />
            </ButtonGroup>
        </div>
    );
}

